/* Markdown image styling */
.prose img {
  border-radius: 0.5rem;
  max-width: 100%;
  height: auto;
  margin-top: 0.5rem;
  margin-bottom: 0.5rem;
}

/* Inline code styling */
.prose :not(pre) > code {
  padding: 0.15em 0.35em;
  border-radius: 0.25rem;
  font-size: 0.85em;
  background-color: #f3f4f6;
}

[data-theme="dark"] .prose :not(pre) > code {
  background-color: var(--bg-secondary);
}

/* Code block styling */
.prose pre {
  border-radius: 0.5rem;
  overflow-x: auto;
}

/* Table styling */
.prose table {
  font-size: 0.875em;
}

.prose th {
  text-align: left;
}

/* Checkbox styling for task lists (GFM) */
.prose input[type="checkbox"] {
  margin-right: 0.4em;
  vertical-align: middle;
}

